# TMscript

새로 만들 TMflow 변수: **var_bridge_ip**(string), **var_done**(bool), **var_scenario_done**(bool) — 3개

## ScriptDecidePosition

```
Socket bridge = var_bridge_ip, 5001
var_done = false
string reply = " "

socket_open("bridge")
socket_sendline("bridge", "next_step")

int wait = 0
while (wait < 60000)
{
    Sleep(500)
    reply = socket_read_string("bridge")
    if (reply != "") { break }
    wait = wait + 500
}
socket_close("bridge")

int idx_ok = String_IndexOf(reply, "OK:")
if (idx_ok >= 0)
{
    string data = String_Substring(reply, 3)
    string[] tokens = String_Split(data, ",")
    var_target_col = String_ToInteger(tokens[0])
    var_target_row = String_ToInteger(tokens[1])
}
else
{
    var_done = true
}
```

## ScriptReportResult

```
string result_str = "ng"
if (var_sd_ok == true)
{
    result_str = "ok"
}

Socket bridge = var_bridge_ip, 5001
string reply = " "
var_scenario_done = false

socket_open("bridge")
socket_sendline("bridge", "step_result " + GetString(var_target_col) + " " + GetString(var_target_row) + " " + result_str + " " + GetString(var_achieved_torque))

int wait = 0
while (wait < 5000)
{
    Sleep(500)
    reply = socket_read_string("bridge")
    if (reply != "") { break }
    wait = wait + 500
}
socket_close("bridge")

int idx = String_IndexOf(reply, "OK:DONE")
if (idx >= 0)
{
    var_scenario_done = true
}
```

